mapper.select:
SELECT COUNT(*)
  FROM EVS_RESUME_INFO RESUME, EVS_OBJECT OBJECT
 WHERE RESUME.SEQ = OBJECT.RESUME_SEQ
   AND RESUME.SEQ = #{resumeSeq, jdbcType=VARCHAR}
   AND OBJECT.SEQ IN (SELECT AFF.EVS_OBJECT_SEQ
                       FROM EVS_AFFIRM AFF
                      WHERE AFF.RESUME_SEQ   = #{resumeSeq,   jdbcType=VARCHAR}
                        AND AFF.AFFIRMOR_ID  = #{adminID,     jdbcType=VARCHAR}
                        AND AFF.AFFIRM_LEVEL = #{affirmLevel, jdbcType=VARCHAR})

SELECT * FROM (
    SELECT INNER_Q.*, ROWNUM AS RN FROM (

        ORDER BY OBJECT.ORDERNO_DEPT, OBJECT.ORDERNO, OBJECT.DATE_STARTED
    ) INNER_Q
    WHERE ROWNUM <= #{start, jdbcType=INTEGER} + #{length, jdbcType=INTEGER}
) WHERE RN > #{start, jdbcType=INTEGER}

SELECT DECODE(GET_CODE_NAME(AFF.EVS_GRADE, #{lang, jdbcType=VARCHAR}),
              'A', 'EX', 'B', 'VG', 'C', 'GD', 'D', 'NI', 'E', 'UN') EVS_GRADE_NAME,
       COUNT(*) CNT
  FROM EVS_AFFIRM AFF
 WHERE AFF.RESUME_SEQ   = #{resumeSeq,   jdbcType=VARCHAR}
   AND AFF.AFFIRMOR_ID  = #{adminID,     jdbcType=VARCHAR}
   AND AFF.AFFIRM_LEVEL = #{affirmLevel, jdbcType=VARCHAR}
   AND AFF.EVS_GRADE IS NOT NULL
 GROUP BY AFF.EVS_GRADE, GET_CODE_NAME(AFF.EVS_GRADE, #{lang, jdbcType=VARCHAR})

SELECT AFF.EVS_OBJECT_SEQ
  FROM EVS_AFFIRM AFF
 WHERE AFF.RESUME_SEQ   = #{resumeSeq,   jdbcType=VARCHAR}
   AND AFF.AFFIRMOR_ID  = #{adminID,     jdbcType=VARCHAR}
   AND AFF.AFFIRM_LEVEL = #{affirmLevel, jdbcType=VARCHAR}

